+#[test]
+fn index_watch_refresh_defaults_stay_bounded() -> Result<(), String> {
+    run_on_large_stack(|| {
+        let cli = parse(&["cass", "index", "--watch"])?;
+
+        match cli.command {
+            Some(Commands::Index {
+                watch: true,
+                watch_interval: 30,
+                watch_once: None,
+                ..
+            }) => Ok(()),
+            other => Err(format!(
+                "expected bounded watch refresh defaults to parse: {other:?}"
+            )),
+        }
+    })
